window.allTests = window.allTests || {};

window.allTests["test_u3_cihan_1"] = [
    {
        soru: "<i>\"İstanbul'un fethi, yalnızca bir şehrin ele geçirilmesi değil, bir çağın kapanıp yeni bir çağın açılmasıydı. Bizans'ın çöküşüyle birlikte Osmanlılar, Doğu Roma'nın varisi olarak kendilerini konumlandırdılar; bu da meşruiyetin kılıç kadar kalem ve sembolle kurulduğunu gösteriyordu.\"</i><br><br><b>İnalcık'ın bu değerlendirmesine göre İstanbul'un fethinin Osmanlı Devleti açısından en temel siyasi sonucu nedir?</b>",
        secenekler: [
            "A) Osmanlı'nın Anadolu'daki Türk beyliklerine karşı üstünlük kurması.",
            "B) Osmanlı'nın Doğu Roma'nın halefi sıfatıyla evrensel bir meşruiyet zemini elde etmesi.",
            "C) İpek Yolu ticaretinin yeniden Osmanlı kontrolüne geçmesi.",
            "D) Karadeniz'in bir iç denize dönüştürülerek ticaret gelirlerinin artması.",
            "E) Balkanlar'daki Hristiyan nüfusun zorla din değiştirmeye tabi tutulması."
        ],
        cevap: "B) Osmanlı'nın Doğu Roma'nın halefi sıfatıyla evrensel bir meşruiyet zemini elde etmesi.",
        aciklama: "İnalcık, fethin askeri boyutunun ötesinde Osmanlı'ya sağladığı evrensel imparatorluk meşruiyetine ve Doğu Roma'nın varisliği statüsüne vurgu yapmaktadır."
    },
    {
        soru: "<i>\"Preveze Deniz Savaşı (1538), Akdeniz'in Osmanlı gölü hâline geldiğini dünyaya ilan eden bir zaferdir. Barbaros Hayreddin Paşa komutasındaki Osmanlı donanması, Andrea Doria önderliğindeki Haçlı ittifak filosunu bozguna uğratmış; bu zaferle birlikte Osmanlı denizciliği, Hristiyan Avrupa'nın en önemli deniz güçlerinden biri olarak tanınmıştır.\"</i><br><br><b>Uzunçarşılı'ya göre Preveze Deniz Savaşı'nın (1538) Osmanlı Devleti'nen deniz politikası açısından en belirleyici sonucu nedir?</b>",
        secenekler: [
            "A) Osmanlı'nın İspanya ile kalıcı bir ittifak kurmasını sağlaması.",
            "B) Kızıldeniz ve Hint Okyanusu'nun Osmanlı kontrolüne girmesi.",
            "C) Osmanlı donanmasının Akdeniz'deki hâkimiyetini uluslararası düzeyde tescil ettirmesi.",
            "D) Venedik'in Osmanlı'ya haraç ödemek zorunda kalması.",
            "E) Osmanlı'nın Cebelitarık Boğazı'nı geçerek Atlantik'e açılması."
        ],
        cevap: "C) Osmanlı donanmasının Akdeniz'deki hâkimiyetini uluslararası düzeyde tescil ettirmesi.",
        aciklama: "Preveze Zaferi, Osmanlı donanmasının Akdeniz'deki mutlak üstünlüğünü ve Avrupa'nın en büyük deniz güçlerinden biri olduğunu kanıtlamıştır."
    },
    {
        soru: "<i>\"Çaldıran Muharebesi (1514), Osmanlı-Safevi mücadelesini şekillendiren temel kırılma noktasıdır. Yavuz Sultan Selim, topçu gücünün üstünlüğünü kullanarak Şah İsmail'i bozguna uğrattı; Safevi süvari saldırılarını ateşli silahlarla püskürttü. Ancak bu zafer, Safevileri tamamen ortadan kaldırmadı; yalnızca doğu sınırını istikrara kavuşturdu.\"</i><br><br><b>Emecen'in bu değerlendirmesine göre Çaldıran Muharebesi'nin (1514) stratejik sınırlılığı nedir?</b>",
        secenekler: [
            "A) Yavuz Sultan Selim'in bu savaştan herhangi bir toprak kazanımı elde edememesi.",
            "B) Osmanlı'nın ateşli silah üstünlüğüne karşın Safevi ordusunu tamamen imha edememesi.",
            "C) Savaşın sonucunun Anadolu'daki Türkmen nüfusunu Safeviler lehine etkilemesi.",
            "D) Osmanlı kuvvetlerinin Tahran'a ulaşamaması nedeniyle siyasi hedefin gerçekleşmemesi.",
            "E) Çaldıran'ın Osmanlı-Memlük savaşlarını hızlandıran bir dönüm noktası olması."
        ],
        cevap: "B) Osmanlı'nın ateşli silah üstünlüğüne karşın Safevi ordusunu tamamen imha edememesi.",
        aciklama: "Zafer askeri açıdan parlak olsa da Safevi devletini ve ideolojik tehdidini tamamen yok edememiş, sadece sınırları geçici olarak güvenceye almıştır."
    },
    {
        soru: "<i>\"Mohaç Muharebesi (1526), Orta Avrupa'nın kaderi açısından belirleyici bir andı. Kanuni Sultan Süleyman, Macar ordusunu iki saat içinde imha etti; Kral II. Lajos hayatını kaybetti. Bu zafer, Orta Avrupa'daki Osmanlı nüfuzunun artık tartışılamaz hâle geldiğini gösterdi. Bununla birlikte Osmanlı, Macaristan'ı doğrudan değil Habsburg baskısına karşı bir tampon bölge olarak değerlendirdi.\"</i><br><br><b>Shaw'a göre Osmanlı'nın Mohaç sonrası Macaristan'a yaklaşımının temel stratejik mantığı nedir?</b>",
        secenekler: [
            "A) Macaristan'ı Osmanlı vilayeti hâline getirerek kalıcı bir yönetim kurmak.",
            "B) Macaristan'ı Habsburglara karşı bir tampon bölge olarak işlev görmesi için yaşatmak.",
            "C) Macaristan üzerinden Kutsal Roma İmparatorluğu ile kalıcı bir ittifak kurmak.",
            "D) Macaristan'daki Protestan nüfusu Osmanlı müttefiki olarak örgütlemek.",
            "E) Macaristan'ı Venedik'e devederek Akdeniz'de diplomatik denge sağlamak."
        ],
        cevap: "B) Macaristan'ı Habsburglara karşı bir tampon bölge olarak işlev görmesi için yaşatmak.",
        aciklama: "Osmanlı, Macaristan'ı Habsburg İmparatorluğu ile arasında koruyucu bir siyasi engel (tampon) olarak kullanarak doğrudan yönetim maliyetini düşürmüştür."
    },
    {
        soru: "<i>\"Fatih Sultan Mehmed'in İtalya seferine gönderdiği kuvvetler, 1480'de Otranto'yu ele geçirdi. Bu, Osmanlı askerinin İtalya topraklarına bastığı ilk andı. Papa ve İtalyan prenslikler büyük bir paniğe kapıldı. Ancak Fatih'in ölümüyle birlikte sefer sürdürülemedi ve Otranto iade edildi. Gene de bu olay, Osmanlı'nın bir kıta gücü olmanın ötesinde evrensel bir imparatorluk iddiasını ciddiye aldığını ortaya koyar.\"</i><br><br><b>Finkel'in bu değerlendirmesine göre Otranto'nun ele geçirilmesinin (1480) Osmanlı İmparatorluğu'nun siyasi vizyonu açısından önemi nedir?</b>",
        secenekler: [
            "A) Osmanlı'nın İtalya'yı kalıcı olarak fethetme stratejisinin ilk adımı olması.",
            "B) Osmanlı'nın salt Anadolu ve Balkan sınırlarını aşarak evrensel bir imparatorluk iddiasını somutlaştırması.",
            "C) Venedik ile imzalanan barış antlaşmasının bozularak Akdeniz'de yeni bir deniz savaşı döneminin başlaması.",
            "D) Osmanlı ordusunun ateşli silah teknolojisini Batı Avrupa'da ilk kez kullanması.",
            "E) Vatikan'ın Osmanlı'yı tanıyan bir diplomatik not göndermesi."
        ],
        cevap: "B) Osmanlı'nın salt Anadolu ve Balkan sınırlarını aşarak evrensel bir imparatorluk iddiasını somutlaştırması.",
        aciklama: "Otranto hamlesi, Osmanlı'nın sadece bölgesel bir güç değil, Roma mirası üzerinde hak iddia eden küresel bir imparatorluk olma vizyonunu simgeler."
    },
    {
        soru: "<i>\"Fatih Sultan Mehmed, İstanbul'un fethinin ardından 'Kayser-i Rum' unvanını benimseyerek Bizans geleneğini sürdürme iddiasında bulundu. Bununla birlikte İslam halifesinin saygınlığını da kazanmak için Abbasi hanedanından sembolik bir törenle halifelik devri aldı. Bu çifte meşruiyet arayışı, Osmanlı egemenliğinin yalnızca askeri değil, hukuki ve dinsel temellere de dayandırıldığını göstermektedir.\"</i><br><br><b>İnalcık'ın bu analizine göre Fatih Sultan Mehmed'in çifte meşruiyet stratejisi hangi tarihsel ihtiyaçtan kaynaklanmaktadır?</b>",
        secenekler: [
            "A) Hristiyan tebaayı Müslüman kimliğine zorla geçirme politikasının hukuki zeminini oluşturmak.",
            "B) Hem Müslüman dünyasına hem Hristiyan Avrupa'ya karşı egemenliğini farklı meşruiyet çerçevelerinde kabul ettirmek.",
            "C) Abbasi hilafetini ihya ederek Arap dünyasını Osmanlı yönetimi altında birleştirmek.",
            "D) Avrupalı devletlerle Bizans hukuku temelinde eşit statüde antlaşmalar imzalamak.",
            "E) Papalık ile dinî bir uzlaşma zemini oluşturarak Haçlı seferlerinin önüne geçmek."
        ],
        cevap: "B) Hem Müslüman dünyasına hem Hristiyan Avrupa'ya karşı egemenliğini farklı meşruiyet çerçevelerinde kabul ettirmek.",
        aciklama: "Farklı toplumsal ve siyasi kitlelere hitap edebilmek için hem Roma (Kayser) hem de İslam (Halife) meşruiyet kaynaklarını aynı anda kullanmıştır."
    },
    {
        soru: "<i>\"Fatih, Akkoyunlu hükümdarı Uzun Hasan'ın batılı devletlerle kurduğu ittifakı kırmak için hem askerî hem diplomatik araçlara başvurdu. Otlukbeli Muharebesi'nde (1473) Osmanlı topçusunun üstünlüğü, Akkoyunlu süvari kuvvetlerini dağıttı. Bununla birlikte Fatih, Venedik ve Papalığın Uzun Hasan'ı destekleme girişimini, Karadeniz ticareti üzerindeki kontrolünü güçlendirerek etkisiz hâle getirdi.\"</i><br><br><b>Tansel'in bu analizine göre Fatih'in Akkoyunlu meselesiyle başa çıkmasında farklı güç araçlarını eş zamanlı kullanması hangi stratejik anlayışı yansıtmaktadır?</b>",
        secenekler: [
            "A) Osmanlı'nın ittifak politikasını reddederek tek taraflı askerî güce dayanan bir dış politika izlemesi.",
            "B) Askerî zafer, ekonomik baskı ve diplomatik yalnızlaştırmayı birleştiren çok boyutlu bir büyük strateji anlayışı.",
            "C) Osmanlı'nın Batılı devletlerle kalıcı bir ittifak kurarak Akkoyunlulara karşı ortak bir cephe oluşturması.",
            "D) Fatih'in topçu teknolojisini Akkoyunlulara satarak doğudaki rakibini zayıflatması.",
            "E) Osmanlı'nın Karadeniz ticaretini engelleyerek Venedik ekonomisini çökerme politikası izlemesi."
        ],
        cevap: "B) Askerî zafer, ekonomik baskı ve diplomatik yalnızlaştırmayı birleştiren çok boyutlu bir büyük strateji anlayışı.",
        aciklama: "Sadece askeri harekat değil; diplomasi ve ticaretin kontrolü gibi 'yumuşak' ve 'sert' güç unsurlarının uyumlu kullanımı büyük stratejiyi ifade eder."
    },
    {
        soru: "<i>\"Yavuz Sultan Selim'in Mısır seferi (1517), yalnızca Memlük Sultanlığı'nı ortadan kaldırmakla kalmadı; Osmanlı'yı Hicaz'ın, yani İslam'ın kutsal şehirlerinin hâmisi konumuna taşıdı. Bu gelişme, Osmanlı sultanlarının İslam dünyasındaki manevi otoritesini temelden dönüştürdü. Artık Osmanlı padişahı yalnızca bir hükümdar değil; İslam'ın koruyucusu ve halifesi olarak algılanmaya başlandı.\"</i><br><br><b>Emecen'in bu analizine göre Mısır seferinin (1517) Osmanlı Devleti'nin ideolojik kimliği üzerindeki dönüştürücü etkisi nedir?</b>",
        secenekler: [
            "A) Osmanlı'nın Hristiyan Avrupa'ya yönelik politikasını Haçlı karşıtı bir söylemle yeniden çerçevelemesi.",
            "B) Osmanlı padişahının İslam dünyasının manevi lideri ve halifesi olarak kabul görmesiyle meşruiyetin yeni bir boyut kazanması.",
            "C) Mısır'ın ekonomik kaynaklarının Osmanlı hazinesine aktarılmasıyla askeri genişlemenin mali temelinin güçlenmesi.",
            "D) Yavuz'un Memlük düzeyinde bir bürokrasiyi benimseyerek idari sistemi dönüştürmesi.",
            "E) Osmanlı'nın Portekiz'e karşı Hint Okyanusu politikasını hızlandırmak için Mısır deniz üslerini ele geçirmesi."
        ],
        cevap: "B) Osmanlı padişahının İslam dünyasının manevi lideri ve halifesi olarak kabul görmesiyle meşruiyetin yeni bir boyut kazanması.",
        aciklama: "Mısır'ın fethi, Osmanlı padişahlarının dünyevi güçlerine İslam dünyasının ruhani liderliği (hilafet) vasfını da eklemiştir."
    },
    {
        soru: "<i>\"Osmanlı-Venedik ilişkisi, sürekli savaş değil aksine çıkara dayalı bir karşılıklı bağımlılık ilişkisiydi. Venedik, Osmanlı limanlarında ticaret imtiyazları (kapitülasyonlar) karşılığında zaman zaman Osmanlı'nın diplomatik hedeflerine destek verdi. Bu ilişki, iki devletin birbirini düşman olarak tanımlarken aynı zamanda ekonomik ortak olarak da değerlendirmesine dayanıyordu.\"</i><br><br><b>İnalcık'ın bu analizine göre Osmanlı-Venedik ilişkisini tanımlamak için en uygun kavramsal çerçeve hangisidir?</b>",
        secenekler: [
            "A) Osmanlı'nın kalıcı üstünlüğüne dayanan tek taraflı bir hegemonya ilişkisi.",
            "B) Siyasi rekabet ile ekonomik iş birliğinin eş zamanlı sürdüğü karmaşık karşılıklı bağımlılık.",
            "C) Haçlı-İslam gerilimi çerçevesinde şekillenen ve uzlaşmaya kapalı düşmanlık.",
            "D) Venedik'in Osmanlı ekonomik sistemi içine tamamen entegre edildiği asimetrik bir sömürge ilişkisi.",
            "E) Ortak Akdeniz ticaretinden eşit kazanım sağlayan simetrik bir iş birliği modeli."
        ],
        cevap: "B) Siyasi rekabet ile ekonomik iş birliğinin eş zamanlı sürdüğü karmaşık karşılıklı bağımlılık.",
        aciklama: "Dönemin siyasi rekabetine rağmen tarafların ekonomik çıkarlar için sürdürdüğü 'faydacı' ilişkiyi (realpolitik) yansıtır."
    },
    {
        soru: "<i>\"Bu denizler artık Osmanlı padişahının gölgesi altındadır. Rüzgâr yelkenleri doldurduğunda hem kaptan hem güverte erleri bilinmelidir ki, bu sularda hâkimiyet Devlet-i Aliyye'nindir. Akdeniz'de hangi liman olursa olsun, oradan çıkan gemi önce padişahın izniyle çıkar, sonra dalgalara teslim olur.\"</i><br><br><b>Piri Reis'in bu ifadelerinde Osmanlı'nın Akdeniz'deki egemenlik anlayışı nasıl tanımlanmaktadır?</b>",
        secenekler: [
            "A) Akdeniz'in açık bir uluslararası deniz olduğu ve tüm devletlerin eşit haklarla yararlanabileceği anlayışı.",
            "B) Akdeniz'deki deniz trafiğinin Osmanlı padişahının onayına tabi olduğu ve egemenliğin limanları ile denizleri kapsadığı anlayışı.",
            "C) Osmanlı'nın Akdeniz'i salt bir ticaret güzergâhı olarak değerlendirdiği ve askerî denetimden kaçındığı görüş.",
            "D) Deniz hâkimiyetinin coğrafi değil ekonomik temellere dayandığı ve gümrük gelirleriyle ölçüldüğü görüş.",
            "E) Piri Reis'in Osmanlı egemenliğini kabul etmemek için metaforları bir örtme stratejisi olarak kullandığı yorum."
        ],
        cevap: "B) Akdeniz'deki deniz trafiğinin Osmanlı padişahının onayına tabi olduğu ve egemenliğin limanları ile denizleri kapsadığı anlayışı.",
        aciklama: "Metin, Osmanlı Devleti'nin Akdeniz'deki suları 'padişahın gölgesi' ve iznine tabi görerek tam bir hakimiyet iddiasında olduğunu belirtir."
    },
    {
        soru: "<i>\"Osmanlı devşirme sistemi, köle asker pratiğini benzersiz bir biçimde dönüştürdü. Hristiyan tebaanın çocukları devlete kazandırılır, İslamlaştırılır ve hem askerî hem bürokratik eğitimden geçirilirdi. Böylece sultanın mutlak sadakatine bağlı, kendi hanedansal hesapları olmayan bir yönetici sınıf oluşturuldu. Bu yapı, devletin aile çıkarlarının üstünde tutulması açısından son derece işlevseldi.\"</i><br><br><b>Imber'in bu analizine göre devşirme sistemi, Osmanlı yönetim anlayışının hangi temel kurumsal sorununu çözmektedir?</b>",
        secenekler: [
            "A) Orduyu etnik açıdan homojen tutma ve Türk asıllı askerlerin ayrıcalığını koruma sorunu.",
            "B) Hanedansal çıkarları devlet çıkarlarının önüne geçirebilecek kalıtımsal aristokrasinin oluşmasını engelleme sorunu.",
            "C) Hristiyan tebaanın eğitim düzeyini yükselterek ekonomik kalkınmayı sağlama sorunu.",
            "D) Yeniçeri ocağının gücünü kısıtlayarak saray kadınlarına daha fazla siyasi ağırlık tanıma sorunu.",
            "E) İslam hukukunda kalıcı köle ticaretini meşrulaştırma sorunu."
        ],
        cevap: "B) Hanedansal çıkarları devlet çıkarlarının önüne geçirebilecek kalıtımsal aristokrasinin oluşmasını engelleme sorunu.",
        aciklama: "Sultan, kendine doğrudan bağlı bir elit sınıf yaratarak yerel aşiret veya aristokratik ailelerin gücünü dengelemiş ve merkeziyetçi yapıyı korumuştur."
    },
    {
        soru: "<i>\"Kanuni Sultan Süleyman'ın 1529 Viyana kuşatması, Osmanlı Batı seferlerinin en uzak noktasını teşkil eder. Kuşatma başarısızlıkla sonuçlandı; erzak ve ikmal güçlükleri, mevsimin gecikmesi ve surların beklenenin üzerinde direnmesi etkili oldu. Ancak bu kuşatma, Habsburg İmparatorluğu'nu Osmanlı tehdidini ciddiye almaya mecbur bıraktı ve iki güç arasındaki uzun soluklu gerginliğin simgesi hâline geldi.\"</i><br><br><b>Uzunçarşılı'nın bu değerlendirmesine göre başarısız Viyana Kuşatması'nın (1529) uzun vadeli stratejik etkisi ne olmuştur?</b>",
        secenekler: [
            "A) Osmanlı'nın Batı seferlerinden vazgeçerek tüm gücünü Doğu cephesine yöneltmesi.",
            "B) Habsburg İmparatorluğu'nun Osmanlı'yı ciddiye alarak uzun süreli bir gerilim içine girmesi.",
            "C) Osmanlı-Fransız ittifakının sona ermesi ve Fransa'nın Habsburg tarafına geçmesi.",
            "D) Viyana surlarının Osmanlı topçusunu engelleyemeyeceğinin anlaşılması üzerine müstahkem mevzi anlayışının değişmesi.",
            "E) Papa'nın tüm Hristiyan devletleri tek çatı altında toplamayı başararak Osmanlı'ya karşı bir Haçlı ordusu oluşturması."
        ],
        cevap: "B) Habsburg İmparatorluğu'nun Osmanlı'yı ciddiye alarak uzun süreli bir gerilim içine girmesi.",
        aciklama: "Kuşatma askeri bir zafer getirmese de Avrupa güç dengesinde Osmanlı'nın varlığını kaçınılmaz bir 'tehdit ve faktör' olarak kabul ettirmiştir."
    },
    {
        soru: "<i>\"Osmanlı'nın 16. yüzyıldaki askerî üstünlüğü yalnızca büyük ordu sayısından değil, bu ordunun merkezî komuta altında disiplinli biçimde koordine edilmesinden kaynaklanıyordu. Topçu ve yeniçeri birlikleri birlikte hareket ederdi; bu kombinasyon, süvari gücüne dayanan dönemin düzenli ordularına karşı belirleyici bir avantaj sağladı. Öte yandan, sefer lojistiği de en az muharebe düzeni kadar titizlikle planlanırdı.\"</i><br><br><b>İnalcık'ın bu analizine göre Osmanlı'nın 16. yüzyıl askerî üstünlüğünün yapısal kaynağı nedir?</b>",
        secenekler: [
            "A) Osmanlı askerlerinin bireysel kahramanlık anlayışı ve dinî motivasyonunun diğer ordulardan üstün olması.",
            "B) Merkezî komuta, disiplinli koordinasyon ve ateşli silah birleşimine dayanan sistematik askerî organizasyon.",
            "C) Osmanlı'nın rakiplerinden çok daha büyük bir nüfusa sahip olması ve bu nüfustan paralı asker devşirmesi.",
            "D) Batı Avrupa'dan gelişmiş silah teknolojisini ithal ederek kendi kuvvetlerini modernize etmesi.",
            "E) Osmanlı'nın rakiplerle asla uzun süreli savaşa girmemesi; aksine kısa ve karar kılıcı savaşları tercih etmesi."
        ],
        cevap: "B) Merkezî komuta, disiplinli koordinasyon ve ateşli silah birleşimine dayanan sistematik askerî organizasyon.",
        aciklama: "Üstünlüğün sırrı; sadece silah değil, farklı birimlerin (topçu, yaya) bir merkezden eş güdümlü yönetildiği disiplinli bir 'makine ordusu' yapısıdır."
    },
    {
        soru: "<i>\"Çaldıran'dan önce Osmanlı-Safevi çatışması dinî boyutu ağır basan bir çerçevede sunulsa da gerçek mesele toprak ve nüfuz üzerindeydi. Şah İsmail'in Anadolu'daki Kızılbaş propagandası, Osmanlı'nın iç düzenini tehdit eden bir unsur hâline gelmişti. Yavuz Sultan Selim, bu propagandaya karşı hem askerî hem ideolojik bir cevap vermek zorundaydı.\"</i><br><br><b>Imber'in bu analizine göre Çaldıran öncesi Osmanlı-Safevi mücadelesini salt dinî bir çatışma olarak nitelendirmek neden yetersiz kalır?</b>",
        secenekler: [
            "A) Çünkü iki taraf da aynı mezhebe mensuptu ve aralarındaki fark yalnızca tarikatlara dayanıyordu.",
            "B) Çünkü gerçek gerilim, dinî farklılığın ardında yatan toprak ve siyasi nüfuz mücadelesini kapsıyordu.",
            "C) Çünkü Yavuz Sultan Selim şeyhülislamın fetvası olmadan savaşa giremezdi ve bu fetva hiçbir zaman verilmedi.",
            "D) Çünkü Safeviler Sünni gelenekle gerçek anlamda uzlaşmış olup Osmanlı'yı yalnızca siyasi gerekçeyle tehdit ediyordu.",
            "E) Çünkü Osmanlı'nın Şii karşıtı tutumu, Anadolu'daki Kızılbaş nüfusun tamamen görmezden gelinmesine yol açmıştır."
        ],
        cevap: "B) Çünkü gerçek gerilim, dinî farklılığın ardında yatan toprak ve siyasi nüfuz mücadelesini kapsıyordu.",
        aciklama: "Din bir meşruiyet aracı olarak kullanılmıştır ancak temel sebep stratejik bir egemenlik ve Anadolu üzerindeki kontrol mücadelesidir."
    },
    {
        soru: "<i>\"Osmanlılar, İpek Yolu'nu doğrudan kontrol etmek yerine zaman zaman alternatif güzergâhları desteklediler. Portekiz'in Ümit Burnu güzergâhını açmasıyla birlikte Osmanlı, Karadeniz ve Akdeniz ticaretini koruma amacıyla hem askerî hem diplomatik politikalar geliştirdi. Bu süreçte ticaret hakimiyeti, bir hedeften çok bir araç olarak işlev gördü.\"</i><br><br><b>İnalcık'ın bu analizine göre Osmanlı'nın 16. yüzyıl ticaret politikasının temel karakteri nasıl tanımlanabilir?</b>",
        secenekler: [
            "A) Osmanlı, serbest ticareti tamamen reddederek korumacı bir ekonomik kapalılık politikası izledi.",
            "B) Osmanlı, ticaret hâkimiyetini bir nihai hedef olarak değil askerî ve diplomatik büyük stratejisinin bir aracı olarak değerlendirdi.",
            "C) Osmanlı, Portekiz'in Ümit Burnu keşfini kullanarak Hint Okyanusu ticaretini kendi kontrolüne almayı başardı.",
            "D) Osmanlı'nın İpek Yolu politikası, ticari çıkarlardan çok dinî zorunluluklara dayanıyordu.",
            "E) Osmanlı, Karadeniz ticaretini Venedik ile ortak yönetmek için kapsamlı bir ittifak kurdu."
        ],
        cevap: "B) Osmanlı, ticaret hâkimiyetini bir nihai hedef olarak değil askerî ve diplomatik büyük stratejisinin bir aracı olarak değerlendirdi.",
        aciklama: "Ticaret, imparatorluğun ayakta kalmasını sağlayan finansman ve lojistik desteği sağladığı için stratejik bir kaldıraç olarak kullanılmıştır."
    }
];
window.allTests = window.allTests || {};

window.allTests["test_u3_cihan_2"] = [
    {
        soru: "<i>\"Kanuni Sultan Süleyman, Zigetvar Kalesi'ni kuşatırken seferin başında hayatını kaybetti. Bu bilgi askerlerden gizlendi; ölümünün duyurulması ordunun moralini bozabilir, sefer düzenini tehdit edebilirdi. Sadrazam Sokullu Mehmed Paşa, haberdar olmayan bir orduyla kuşatmayı sürdürdü ve kale 1566'da teslim oldu.\"</i><br><br><b>Uzunçarşılı'nın bu aktarımına göre Zigetvar'da Kanuni'nin ölümünün gizlenmesi olayı, Osmanlı devlet yönetimi açısından hangi yapısal özelliği gözler önüne sermektedir?</b>",
        secenekler: [
            "A) Osmanlı ordusunun sultanın fiziksel varlığına bağımlı olduğu ve sultanın olmadığı savaşlarda dağıldığı.",
            "B) Sokullu Mehmed Paşa'nın uzun süreli sadakat ilişkisinin, merkezin yokluğunda dahi kurumsal sürekliliği sağlayabildiği.",
            "C) Osmanlı'nın ölüm haberlerini gizlemek için yazılı iletişimden kaçındığı ve yalnızca sözlü habercilere dayandığı.",
            "D) Yeniçerilerin padişahsız savaşmayı reddeden bir yemini olduğu ve Sokullu'nun bu yeminden muaf tutulduğu.",
            "E) Zigetvar'ın stratejik açıdan önemsiz olduğu ve yalnızca sembolik değeri için kuşatıldığı."
        ],
        cevap: "B) Sokullu Mehmed Paşa'nın uzun süreli sadakat ilişkisinin, merkezin yokluğunda dahi kurumsal sürekliliği sağlayabildiği.",
        aciklama: "Bu olay, devlet bürokrasisinin ve sadrazamlık makamının hükümdarın yokluğunda dahi sistemi işletebilecek bir kurumsal sağlamlığa ulaştığını gösterir."
    },
    {
        soru: "<i>\"Osmanlı-Safevi mücadelesi, 1555 Amasya Antlaşması ile ilk kez resmî bir ateşkes zeminine oturdu. Bu antlaşma yalnızca sınır çizmekle kalmadı; aynı zamanda iki tarafın birbirinin egemenliğini zımnen tanımasına ve Şii propagandanın Osmanlı topraklarında sınırlandırılmasına yönelik bir uzlaşma sundu. Böylece iki süper güç arasındaki ilişki, sürekli savaştan yönetilen bir rekabete dönüştü.\"</i><br><br><b>Emecen'in bu analizine göre 1555 Amasya Antlaşması'nın Osmanlı-Safevi ilişkilerini dönüştürmedeki temel işlevi nedir?</b>",
        secenekler: [
            "A) Osmanlı'nın Safeviler üzerinde kalıcı bir askerî zafer elde etmesi ve sınırı tek taraflı çizmesi.",
            "B) Sürekli savaş ortamından her iki tarafın egemenliğini karşılıklı tanıyan ve rekabeti yöneten bir düzene geçiş.",
            "C) Amasya Antlaşması'nın Osmanlı-Safevi birleşmesini sağlayarak ortak bir Portekiz karşıtı cephe oluşturması.",
            "D) Osmanlı'nın Şii mezhebini kendi topraklarında resmen tanıyarak Kızılbaş tehditini kalıcı biçimde ortadan kaldırması.",
            "E) Safevi Şahı'nın Sünni mezhebine geçerek Osmanlı padişahının dinî otoritesini kabul etmesi."
        ],
        cevap: "B) Sürekli savaş ortamından her iki tarafın egemenliğini karşılıklı tanıyan ve rekabeti yöneten bir düzene geçiş.",
        aciklama: "Amasya Antlaşması, askeri çözümün imkansızlığının anlaşıldığı bir noktada, iki büyük devletin diplomatik kurallar çerçevesinde rekabet etmesini sağlayan bir meşruiyet zemini kurmuştur."
    },
    {
        soru: "<i>\"İnebahtı Deniz Muharebesi (1571), Osmanlı donanmasına büyük kayıplar yaşattı. Ancak Shaw'a göre bu yenilgi, Osmanlı'nın deniz hâkimiyetini kalıcı olarak yitirdiği anlamına gelmiyordu. Osmanlı tersaneleri, kaybedilen gemileri kısa sürede telafi etti. İspanya ve Venedik ise ittifak içi çıkar çatışmaları nedeniyle kazanılan zaferden gereken stratejik sonuçları çıkaramadı.\"</i><br><br><b>Shaw'ın bu değerlendirmesine göre İnebahtı'nın (1571) Osmanlı açısından sınırlı bir stratejik yenilgi olarak kalmasının temel nedeni nedir?</b>",
        secenekler: [
            "A) Osmanlı donanmasının İnebahtı'da yalnızca ön kuvvetlerini kullanmış olması ve ana filonun zarar görmemesi.",
            "B) Osmanlı tersanelerinin hızlı toparlanma kapasitesi ile Hristiyan ittifakının stratejik avantajı kullanamaması.",
            "C) Papa'nın Venedik ve İspanya arasındaki anlaşmazlıkları çözerek İnebahtı zaferini kalıcı bir Osmanlı karşıtı ittifaka dönüştürmesi.",
            "D) Osmanlı'nın kaybettiği deniz gücünü yerine koymak yerine Kuzey Afrika'daki kara kuvvetlerini güçlendirmeyi tercih etmesi.",
            "E) İnebahtı yenilgisinin aslında Osmanlı'nın kasıtlı olarak geri çekilme taktiğinin bir parçası olması."
        ],
        cevap: "B) Osmanlı tersanelerinin hızlı toparlanma kapasitesi ile Hristiyan ittifakının stratejik avantajı kullanamaması.",
        aciklama: "Askeri bir yıkım olmasına rağmen, Osmanlı'nın üretim kapasitesi ve Haçlı ittifakının siyasi bölünmüşlüğü zaferin stratejik bir kazanıma dönüşmesini engellemiştir."
    },
    {
        soru: "<i>\"1639 Kasr-ı Şirin Antlaşması, Osmanlı-Safevi savaşlarının en uzun aralıklı ateşkesini sağladı. Bu antlaşma, bugünkü Türkiye-İran sınırının temelini oluşturmaktadır. İki taraf da birbirini egemen devlet olarak tanımış; Mezopotamya Osmanlı'ya, Azerbaycan'ın büyük bölümü ise Safevi'ye bırakılmıştır. Antlaşmanın kalıcılığı, her iki tarafın da artık sınırı değiştirme konusunda önemli bir maliyet hesabı yaptığını göstermektedir.\"</i><br><br><b>Finkel'in bu analizine göre Kasr-ı Şirin Antlaşması'nın (1639) kalıcılığı nasıl açıklanabilir?</b>",
        secenekler: [
            "A) Osmanlı'nın Safevileri askeri olarak kesin bir yenilgiye uğratması ve Safevi'nin antlaşma dışında seçeneğinin kalmaması.",
            "B) Her iki tarafın sınırı değiştirmenin maliyetini kabul edilemez bulmasından kaynaklanan karşılıklı caydırıcılık dengesi.",
            "C) Antlaşmanın Avrupa güçlerinin garantörlüğüne alınmış olması ve bu nedenle ihlalinin diplomatik sonuçlarının ağır olması.",
            "D) Osmanlı ve Safevi'nin bu dönemde artan iç sorunları nedeniyle dış savaşa kapasitelerinin kalmaması.",
            "E) İslam hukukunun Müslüman devletler arasındaki antlaşmaları ihlal etmeyi dinî açıdan yasaklamış olması."
        ],
        cevap: "B) Her iki tarafın sınırı değiştirmenin maliyetini kabul edilemez bulmasından kaynaklanan karşılıklı caydırıcılık dengesi.",
        aciklama: "Taraflar birbirini tamamen yok edemeyeceklerini anlamış ve mevcut sınırları korumanın, yeni bir savaşa girmekten daha kârlı olduğu rasyonel kararına varmışlardır."
    },
    {
        soru: "<i>\"Belgrad'ın fethi (1521), Kanuni Sultan Süleyman'ın ilk büyük askerî başarısıydı. Bu fetih, Osmanlı'nın Orta Avrupa'ya açılan kapısını araladı; beş yıl sonraki Mohaç zaferinin ve Viyana kuşatmasının önünü açtı. Belgrad, iki kuşak boyunca Osmanlı'ya direnmiş ve hatta Fatih Sultan Mehmed'i bile durduran bir kaleydi.\"</i><br><br><b>İnalcık'ın bu değerlendirmesine göre Belgrad'ın fethinin (1521) Osmanlı'nın Avrupa stratejisi açısından önemi nedir?</b>",
        secenekler: [
            "A) Belgrad'ın fethi, Osmanlı'nın Orta Avrupa seferlerinin zirveye ulaştığı son büyük askerî zaferdir.",
            "B) Belgrad, iki kuşak boyunca Osmanlı'ya direnmiş olduğundan fethi, Orta Avrupa'ya açılan stratejik kapının açılmasıdır.",
            "C) Belgrad fethinin asıl önemi, Osmanlı'nın Viyana'yı daha önce alma fırsatını kaçırdığını ortaya koymasındadır.",
            "D) Belgrad'ın fethiyle Osmanlı, Macaristan'ı tamamen kontrol altına alarak kalıcı bir valilik kurmuştur.",
            "E) Belgrad, salt sembolik önemi olan bir kale olup fethi Osmanlı'ya somut bir stratejik kazanım sağlamamıştır."
        ],
        cevap: "B) Belgrad, iki kuşak boyunca Osmanlı'ya direnmiş olduğundan fethi, Orta Avrupa'ya açılan stratejik kapının açılmasıdır.",
        aciklama: "Belgrad'ın düşmesi, Macaristan ovasına ve ardından Avusturya içlerine yapılacak akınlar için engelleyici son büyük kaleyi ortadan kaldırmıştır."
    },
    {
        soru: "<i>\"Rodos'un fethi (1522), Osmanlı'nın Doğu Akdeniz'deki hâkimiyetini pekiştiren stratejik bir hamledir. Saint-Jean Şövalyeleri, Osmanlı deniz yollarına sürekli baskı yapıyor; Mısır ve Suriye'ye giden gemileri tehdit ediyordu. Kanuni Sultan Süleyman, hem kara hem deniz kuvvetlerinin eş güdümlü harekâtıyla adayı aldı. Bu zafer, Orta Doğu ticaret yollarını güvence altına almakla kalmayıp Osmanlı donanmasının Akdeniz'deki özgürlük alanını genişletti.\"</i><br><br><b>Imber'in bu analizine göre Rodos'un fethinin (1522) Osmanlı'nın Doğu Akdeniz egemenliği açısından taşıdığı çift boyutlu işlev nedir?</b>",
        secenekler: [
            "A) Hristiyan Şövalyelerden alınan fidye gelirleriyle Osmanlı hazinesini güçlendirme ve Papalıkla müzakere zemini oluşturma.",
            "B) Doğu Akdeniz ticaret yollarını tehdit eden bir üssü ortadan kaldırma ve Osmanlı donanmasının hareket özgürlüğünü artırma.",
            "C) Venedik'in Ege adaları üzerindeki kontrolünü kırma ve Osmanlı adacılık politikasını başlatma.",
            "D) Rodos üssünden saldıran Portekiz gemilerini engelleme ve Kızıldeniz'e güvenli ulaşım sağlama.",
            "E) Osmanlı'nın Kıbrıs'a karşı gerçekleştireceği büyük harekâtın lojistik merkezini kurma."
        ],
        cevap: "B) Doğu Akdeniz ticaret yollarını tehdit eden bir üssü ortadan kaldırma ve Osmanlı donanmasının hareket özgürlüğünü artırma.",
        aciklama: "Rodos'un fethiyle hem hac ve ticaret yollarının güvenliği sağlanmış hem de denizlerdeki 'çapraz baskı' unsuru yok edilerek hareket alanı genişletilmiştir."
    },
    {
        soru: "<i>\"Fatih Sultan Mehmed döneminde gerçekleştirilen fetihler tek bir coğrafi yöne yönelik değildi. Kuzey'de Karadeniz'i bir iç denize dönüştürme hedefi, güneyde Memlük sınırına yaklaşma çabası ve batıda İtalya harekâtının eş zamanlı yürütülmesi, Fatih'in coğrafi hayal gücünün ne denli geniş olduğunu ortaya koymaktadır. Bu çok yönlü politika, mevcut kaynakları zaman zaman son derece zorladı.\"</i><br><br><b>Tansel'in bu analizine göre Fatih döneminin çok yönlü fetih politikasının temel çelişkisi nedir?</b>",
        secenekler: [
            "A) Fatih'in büyük coğrafi vizyonunun mevcut kaynaklar üzerinde ciddi baskı oluşturması.",
            "B) Fatih'in çok yönlü politikasının İslam dünyasında meşruiyet sorunlarına yol açması.",
            "C) Osmanlı ordusunun birden fazla cephede savaşmaya uygun olmayan geleneksel yapısı.",
            "D) Yeniçerilerin Batı seferlerini kabul etmeyerek yalnızca Doğu harekâtlarına katılması.",
            "E) Fatih'in genişleme politikasının Bizans toprak taleplerini çözümsüz bırakması."
        ],
        cevap: "A) Fatih'in büyük coğrafi vizyonunun mevcut kaynaklar üzerinde ciddi baskı oluşturması.",
        aciklama: "Aynı anda hem Karadeniz'de, hem Balkanlarda hem de Akdeniz'de genişleme çabası, devletin mali ve askeri imkanlarının sınırlarını zorlamıştır."
    },
    {
        soru: "<i>\"Kıbrıs'ın fethi (1570–71), Osmanlı'nın Doğu Akdeniz stratejisinin son büyük halkasıydı. Venedik'e ait bu ada, Osmanlı ticaret ve deniz yollarının ortasında yabancı bir güç varlığı anlamına geliyordu. Fetih sonrasında Doğu Akdeniz'de Osmanlı hâkimiyeti tartışmasız hâle gelse de hemen ardından gelen İnebahtı yenilgisi, bu hâkimiyetin salt askerî zafer üzerine kurulu olamayacağını gösterdi.\"</i><br><br><b>Finkel'in bu değerlendirmesine göre Kıbrıs fethinin (1570–71) ardından yaşanan İnebahtı yenilgisinin ortaya koyduğu temel stratejik ders nedir?</b>",
        secenekler: [
            "A) Kıbrıs'ın alınmasının stratejik açıdan gereksiz olduğu ve Venedik ile diplomasi yolunun denenmesi gerektiği.",
            "B) Deniz hâkimiyetinin salt askerî zaferle değil, kalıcı deniz gücü kapasitesiyle pekiştirilmesi gerektiği.",
            "C) İnebahtı yenilgisinin Osmanlı'yı Kıbrıs'ı Venedik'e iade etmek zorunda bıraktığı ve fethin sonuçsuz kaldığı.",
            "D) Osmanlı'nın artık kara gücüne yoğunlaşması ve deniz hâkimiyetinden vazgeçmesi gerektiği.",
            "E) Kıbrıs'ın fethi ile İnebahtı arasında doğrudan bir nedensellik bağının bulunmadığı."
        ],
        cevap: "B) Deniz hâkimiyetinin salt askerî zaferle değil, kalıcı deniz gücü kapasitesiyle pekiştirilmesi gerektiği.",
        aciklama: "Kıbrıs'ın alınması toprak kazanımıdır; İnebahtı ise denizde varlığı koruyacak 'sürdürülebilir donanma gücü'nün (capacity) önemini hatırlatan bir darbedir."
    },
    {
        soru: "<i>\"Osmanlı'nın Hint Okyanusu politikası, 16. yüzyılda Portekiz varlığına karşı geliştirilmiş fakat sınırlı başarıyla sonuçlanmıştır. Osmanlı donanması zaman zaman Aden ve Diu çevresinde operasyonlar gerçekleştirmiş; ancak Hint Okyanusu'nun kendine özgü denizcilik koşulları, Akdeniz teknoloji ve tecrübesine sahip Osmanlı denizcilerini zorlayan bir ortam sunmuştur.\"</i><br><br><b>İnalcık'ın bu analizine göre Osmanlı'nın Hint Okyanusu'ndaki sınırlı başarısının yapısal nedeni nedir?</b>",
        secenekler: [
            "A) Osmanlı'nın Hint Okyanusu politikasını tamamen terk etmiş olması.",
            "B) Osmanlı donanmasının Akdeniz koşullarına göre şekillenmiş teknoloji ve tecrübesinin Hint Okyanusu'nun farklı ortamında yetersiz kalması.",
            "C) Osmanlı'nın Hint Okyanusu operasyonlarını finanse edecek mali kaynaklardan yoksun olması.",
            "D) Portekiz'in Osmanlı'dan çok daha büyük bir donanmaya sahip olması.",
            "E) Osmanlı'nın Hint Okyanusu yerine Atlantik politikasını önceliklendirmesi."
        ],
        cevap: "B) Osmanlı donanmasının Akdeniz koşullarına göre şekillenmiş teknoloji ve tecrübesinin Hint Okyanusu'nun farklı ortamında yetersiz kalması.",
        aciklama: "Açık deniz (okyanus) denizciliği ile Akdeniz'in iç deniz geleneği arasındaki teknik fark, Osmanlı'nın okyanuslarda Portekiz ile rekabetini zorlaştıran temel etkendir."
    },
    {
        soru: "<i>\"Kanuni Sultan Süleyman'ın Fransa ile kurduğu ittifak (1535 kapitülasyonları), Osmanlı'nın yalnızca bir İslam devleti olmadığını; Avrupa güç dengesi hesapları içinde rasyonel bir aktör olarak yer aldığını kanıtlamaktadır. Ortak düşman Habsburg karşısında iki farklı inançtan devletin ittifak kurması, dönemin dinî savaş ideolojisinin ötesinde pragmatik bir dış politika anlayışını yansıtıyordu.\"</i><br><br><b>Finkel'in bu analizine göre Osmanlı-Fransız ittifakının (1535) en dikkat çekici tarihsel anlamı nedir?</b>",
        secenekler: [
            "A) Fransa'nın Osmanlı'nın üstünlüğünü tanıyarak Müslüman bir devletle eşit statüde antlaşma imzalaması.",
            "B) Osmanlı'nın dinî savaş ideolojisinin ötesinde Avrupa güç dengesi içinde pragmatik bir dış politika aktörü olarak hareket etmesi.",
            "C) Osmanlı-Fransız ittifakının Hristiyanlığı tamamen siyaset dışı bıraktığı.",
            "D) Kanuni'nin dinî gerekçeleri tamamen reddederek laik bir dış politika anlayışını benimsemesi.",
            "E) Fransa'nın kapitülasyonlar sayesinde Osmanlı'dan daha fazla ticari avantaj sağlaması."
        ],
        cevap: "B) Osmanlı'nın dinî savaş ideolojisinin ötesinde Avrupa güç dengesi içinde pragmatik bir dış politika aktörü olarak hareket etmesi.",
        aciklama: "Bu ittifak, Osmanlı'nın ideolojik (dini) sınırlar yerine jeopolitik çıkarları ve Avrupa içindeki rakipleri dengeleme stratejisini (realpolitik) önemsediğini gösterir."
    },
    {
        soru: "<i>\"Osmanlı tahrir defterlerinde, fethedilen bölgelerdeki 'adet-i ağnam' (koyun vergisi) veya 'resm-i çift' (arazi vergisi) gibi kalemlerin, çoğu zaman önceki yerel yönetimlerin aldığı vergi oranlarından daha düşük belirlendiği görülür. Bu bilinçli bir 'vergi indirimi' politikasıydı.\"</i><br><br><b>Bu vergi politikasının istimalet (hoşgörü) ve kalıcılık açısından önemi nedir?</b>",
        secenekler: [
            "A) Devletin mali krize girmesini hızlandıran başarısız bir ekonomi politikasıdır.",
            "B) Yerel halkın eski idarecilere göre Osmanlı'yı daha adil ve rasyonel bulmasını sağlayarak isyan ihtimalini düşüren stratejik bir tercihtir.",
            "C) Osmanlı'nın vergi toplamayı bilmediğini gösteren bürokratik bir eksikliktir.",
            "D) Yalnızca Müslüman köylülerin zenginleşmesini sağlamak amacıyla yapılmıştır.",
            "E) Eski yöneticilerin yeniden bölgeye dönmesini teşvik eden bir uygulamadır."
        ],
        cevap: "B) Yerel halkın eski idarecilere göre Osmanlı'yı daha adil ve rasyonel bulmasını sağlayarak isyan ihtimalini düşüren stratejik bir tercihtir.",
        aciklama: "Vergi adaleti ve yükün hafifletilmesi, fethedilen halkın Osmanlı nizamına gönüllü uyum sağlamasını (istimalet) sağlayan en etkili araçlardan biridir."
    },
    {
        soru: "<i>\"Yavuz Sultan Selim'in doğu seferleri sırasında (1514-1517) ele geçirilen İpek ve Baharat Yolu güzergâhları, Osmanlı hazinesine muazzam bir gelir akışı sağladı. Ancak bu ticari üstünlük, kısa süre sonra Avrupalıların Ümit Burnu'nu keşfetmesiyle yeni bir küresel rekabet ortamına taşındı.\"</i><br><br><b>Bu metne göre Yavuz dönemindeki ekonomik kazanımlar ve karşılaşılan yeni durum nasıl özetlenebilir?</b>",
        secenekler: [
            "A) Kazanımlar tamamen kalıcı olmuş ve Avrupa ticareti çökmüştür.",
            "B) Geleneksel ticaret yollarının denetimi sağlanmış, ancak Coğrafi Keşifler bu üstünlüğü küresel bir rekabetle karşı karşıya bırakmıştır.",
            "C) Osmanlı, Baharat Yolu'nu aldıktan sonra Akdeniz ticaretinden tamamen vazgeçmiştir.",
            "D) Portekiz ve İspanya'nın keşifleri Osmanlı ekonomisine hiçbir zarar vermemiştir.",
            "E) Yavuz'un seferleri ekonomik değil sadece dini amaçlıdır."
        ],
        cevap: "B) Geleneksel ticaret yollarının denetimi sağlanmış, ancak Coğrafi Keşifler bu üstünlüğü küresel bir rekabetle karşı karşıya bırakmıştır.",
        aciklama: "Doğu ticaret yolları Osmanlı kontrolüne geçse de, Avrupa'nın okyanuslara yönelmesi bu kontrolün mutlak karlılığını ve stratejik tekelini sarsmıştır."
    },
    {
        soru: "<i>\"Fatih Sultan Mehmed, İstanbul'u fethettikten sonra şehri yeniden inşa etmek amacıyla farklı bölgelerden zanaatkarları ve tüccarları buraya getirmiştir. Bu göç ve iskân politikası, İstanbul'un sadece siyasi değil, aynı zamanda ekonomik bir üretim merkezine dönüşmesini hedefliyordu.\"</i><br><br><b>İskân politikasının İstanbul özelindeki temel hedefi nedir?</b>",
        secenekler: [
            "A) Şehri sadece bir askeri üs olarak kullanmak.",
            "B) İstanbul'un ticari ve üretim potansiyelini canlandırarak kentsel ekonomiyi kurumsallaştırmak.",
            "C) Hristiyan nüfusu tamamen şehirden temizlemek.",
            "D) Şehri sadece tarım üretimine ayırmak.",
            "E) Kütüphanelerdeki kitapları Anadolu'ya kaçırmak."
        ],
        cevap: "B) İstanbul'un ticari ve üretim potansiyelini canlandırarak kentsel ekonomiyi kurumsallaştırmak.",
        aciklama: "Kentsel canlanma, sadece binalarla değil, o binalarda ekonomik faaliyet yürütecek yetişmiş insan gücünün (zanaatkar, tüccar) planlı yerleşimiyle mümkündür."
    },
    {
        soru: "<i>\"Osmanlı İmparatorluğu'nda ulema sınıfı, sadece dini işlerden değil, aynı zamanda eğitim ve hukuk sisteminden de sorumluydu. Bir kadı, hem mahkemeyi yönetir hem de yerel yönetimin adalet dairesine uygunluğunu denetlerdi. Bu durum, ilmiye sınıfının devlet hiyerarşisindeki kilit konumunu gösterir.\"</i><br><br><b>İlmiye sınıfının çok yönlü görevleri neyi kanıtlar?</b>",
        secenekler: [
            "A) Dinin ve hukukun devlet idaresinin ayrılmaz bir parçası olduğunu ve ulemanın idari denetim gücünü.",
            "B) Medreselerin orduya komutan yetiştirdiğini.",
            "C) İlmiyenin padişahın yetkilerini tamamen elinden aldığını.",
            "D) Kadıların sadece camilerde görev yaptığını.",
            "E) Eğitim sisteminin tamamen ulemadan bağımsız olduğunu."
        ],
        cevap: "A) Dinin ve hukukun devlet idaresinin ayrılmaz bir parçası olduğunu ve ulemanın idari denetim gücünü.",
        aciklama: "Ulemanın yargı ve eğitimdeki rolü, devletin meşruiyetini hukuk ve din süzgecinden geçirerek sağlamasını ve idari mekanizmaların denetlenmesini garanti altına alır."
    },
    {
        soru: "<i>\"15. ve 16. yüzyıllarda Osmanlı medreselerinde matematik ve astronomi çalışmalarının altın çağı yaşanmıştır. Ali Kuşçu ve Molla Fenari gibi alimler, rasyonel düşünce ile dini inancı harmanlayarak 'hikmet' temelli bir bilim anlayışı geliştirmişlerdir. Bu anlayış, bilginin bir bütün olduğunu savunur.\"</i><br><br><b>Osmanlı'nın 'hikmet' temelli bilim anlayışının özelliği nedir?</b>",
        secenekler: [
            "A) Pozitif bilimlerin dini inançlara aykırı görülerek yasaklanması.",
            "B) Akli ilimler ile nakli ilimlerin birbirini tamamlayan bir bütün olarak görülmesi.",
            "C) Sadece tıp eğitimine önem verilmesi.",
            "D) Bilimin sadece saray içinde gizli bir uğraş olması.",
            "E) Deney ve gözlemin tamamen reddedilmesi."
        ],
        cevap: "B) Akli ilimler ile nakli ilimlerin birbirini tamamlayan bir bütün olarak görülmesi.",
        aciklama: "Hikmet anlayışı, evrenin işleyişini anlamayı (bilim) yaratılış gerçeğini kavramanın (inanç) bir yolu olarak gören bütüncül bir perspektiftir."
    }
];
window.allTests = window.allTests || {};

window.allTests["test_u3_cihan_4"] = [
    {
        soru: "<i>\"Saliba: 'İslam astronomi geleneğinin Batı'ya aktarımında Osmanlı alimlerinin rolü yeterince araştırılmamıştır. Ali Kuşçu'nun İstanbul'a getirdiği astronomi birikimi, hem Osmanlı medreselerini hem de Avrupa'nın bilim devrimine uzanan tartışmaları dolaylı biçimde etkilemiştir.'\"</i><br><br><b>Saliba'ya göre Osmanlı bilim geleneğinin uluslararası tıp ve astronomi tarihindeki önemi nedir?</b>",
        secenekler: [
            "A) Osmanlı'nın bilimde tamamen Batı'yı taklit ettiği.",
            "B) Osmanlı alimlerinin İslam bilim mirasını hem koruyan hem de küresel bilim tartışmalarına aktaran aktif bir rol oynaması.",
            "C) Ali Kuşçu'nun sadece İstanbul ile sınırlı bir etki yaratması.",
            "D) Osmanlı medreselerinde sadece dini derslerin okutulmuş olması.",
            "E) Osmanlı biliminin Avrupa'daki Rönesans'tan hiçbir şekilde etkilenmediği."
        ],
        cevap: "B) Osmanlı alimlerinin İslam bilim mirasını hem koruyan hem de küresel bilim tartışmalarına aktaran aktif bir rol oynaması.",
        aciklama: "Osmanlı bilim dünyası, özellikle astronomide ulaşılan seviyeyle, bilginin hem Doğu hem de Batı arasında akışını sağlayan bir merkez işlevi görmüştür."
    },
    {
        soru: "<i>\"Osmanlı Devleti'nin fethettiği bölgelerde izlediği nüfus politikası — sürgün ve iskân — salt demografik bir araç değildi. Stratejik geçitler, yeni fethedilen şehirler ve potansiyel isyan odakları bu politikanın doğrudan hedefi oluyordu.\"</i><br><br><b>İnalcık'ın bu analizine göre Osmanlı'nın iskân politikasının öncelikli işlevi nedir?</b>",
        secenekler: [
            "A) Tarım gelirlerini artırmak amacıyla köylüleri yerinden etmek.",
            "B) Balkan nüfusunu asimile ederek dil birliği sağlamak.",
            "C) Stratejik önem taşıyan bölgeleri, isyan riskini azaltacak ve yönetimi güçlendirecek bir nüfus yapısıyla biçimlendirmek.",
            "D) Sadece Hristiyan nüfusu Anadolu'ya taşımak.",
            "E) Anadolu'daki şehirlerin kalabalıklığını azaltmak."
        ],
        cevap: "C) Stratejik önem taşıyan bölgeleri, isyan riskini azaltacak ve yönetimi güçlendirecek bir nüfus yapısıyla biçimlendirmek.",
        aciklama: "İskân, fethin kalıcı olmasını sağlamak ve bölgenin askeri güvenliğini sivil nüfusla tahkim etmek için kullanılan bir 'idari mühendislik'tir."
    },
    {
        soru: "<i>\"Osmanlı'nın 16. yüzyıldaki başarısı, merkezi hazine ile taşradaki tımar sistemi arasındaki mükemmel dengeden kaynaklanıyordu. Hazine, saray ve yeniçeri ordusunu finanse ederken; tımar sistemi, eyaletlerde devasa bir süvari ordusunu devletin nakit harcaması olmadan besliyordu.\"</i><br><br><b>Bu metne göre Osmanlı mali-askeri sisteminin en büyük avantajı nedir?</b>",
        secenekler: [
            "A) Tüm askerlerin hazineden düzenli maaş alması.",
            "B) Savaş masraflarının tamamının dış borçla karşılanması.",
            "C) Hazineden nakit para çıkışı olmadan toprağa dayalı büyük bir askeri güç (sipahiler) hazır tutulabilmesi.",
            "D) Tımar sisteminin sadece tarım üretimine odaklanmış olması.",
            "E) Yeniçerilerin hiçbir zaman sefere gitmemesi."
        ],
        cevap: "C) Hazineden nakit para çıkışı olmadan toprağa dayalı büyük bir askeri güç (sipahiler) hazır tutulabilmesi.",
        aciklama: "Toprak gelirlerinin doğrudan asker beslemeye (cebelü) ayrılması, devletin sınırlı nakit kaynaklarını merkezi bürokrasi ve teknik birlikler için saklamasına olanak vermiştir."
    },
    {
        soru: "<i>\"16. yüzyıl Osmanlı ekonomisinde 'iaşecilik' ilkesi esastı. Bu ilke, halkın temel tüketim ihtiyaçlarının (buğday, et, yağ) piyasada bol, ucuz ve kaliteli bulunmasını her şeyin üstünde tutardı. Bu nedenle devlet, ihracatı kısıtlar ve fiyatlara müdahale ederdi.\"</i><br><br><b>İaşecilik ilkesinin temel toplumsal amacı nedir?</b>",
        secenekler: [
            "A) Tüccarların daha fazla kâr etmesini sağlamak.",
            "B) Tüketiciyi koruyarak toplumsal huzuru ve siyasi istikrarı garanti altına almak.",
            "C) Avrupa devletlerine daha fazla mal satmak.",
            "D) Sanayi üretimini tamamen durdurmak.",
            "E) Sadece padişahın mutfağını doyurmak."
        ],
        cevap: "B) Tüketiciyi koruyarak toplumsal huzuru ve siyasi istikrarı garanti altına almak.",
        aciklama: "Osmanlı iktisat anlayışı, serbest piyasa kârından ziyade 'kamu yararı' ve 'toplumsal düzen' (iaşe) üzerine kuruluydu."
    },
    {
        soru: "<i>\"Osmanlı'da 'padişah fermanı' ile düzenlenen örfi hukuk, şeriatın boş bıraktığı alanlarda (idare, maliye, ceza) devlete büyük bir esneklik sağlamıştır. Bu sayede imparatorluk, farklı coğrafyalardaki yerel adetleri de dikkate alan kanunnameler hazırlayabilmiştir.\"</i><br><br><b>Örfi hukukun Osmanlı idari sistemine en büyük katkısı nedir?</b>",
        secenekler: [
            "A) Şeriatı tamamen geçersiz kılmak.",
            "B) Devlet yönetimine ve yerel ihtiyaçlara hızlı, esnek ve pratik çözümler sunmak.",
            "C) Padişahın yetkilerini ulemaya devretmek.",
            "D) Hukukun her bölgede tamamen aynı uygulanmasını sağlamak.",
            "E) Sadece askeri konuları düzenlemek."
        ],
        cevap: "B) Devlet yönetimine ve yerel ihtiyaçlara hızlı, esnek ve pratik çözümler sunmak.",
        aciklama: "Kanunnameler, devletin değişen şartlara ve fethettiği yeni toplumların geleneklerine uyum sağlamasını kolaylaştıran 'idari araçlar'dır."
    },
    {
        soru: "<i>\"Osmanlı döneminde kütüphaneler, 'hafız-ı kütüb' adı verilen uzman görevliler tarafından yönetilirdi. Kitapların kaydı tutulur, çalınması veya zarar görmesi önlenirdi. Bu sistem, bilginin kamusal bir miras olarak korunmasını ve gelecek nesillere aktarılmasını sağlamıştır.\"</i><br><br><b>Kütüphane organizasyonu Osmanlı'da bilgiye verilen hangi değeri yansıtır?</b>",
        secenekler: [
            "A) Kitapların sadece süs eşyası olarak görülmesini.",
            "B) Bilginin korunması gereken kurumsal ve kutsal bir emanet olarak kabul edilmesini.",
            "C) Okuma yazmanın sadece saraylılara özgü kalmasını.",
            "D) Kitap sayısının azlığını.",
            "E) Yazma eserlerin modern kitaplardan daha değersiz görüldüğünü."
        ],
        cevap: "B) Bilginin korunması gereken kurumsal ve kutsal bir emanet olarak kabul edilmesini.",
        aciklama: "Hafız-ı kütüb gibi kadroların ihdas edilmesi, kütüphanelerin tesadüfi bir birikim değil, bilinçli ve korunan birer devlet kurumu olduğunu gösterir."
    },
    {
        soru: "<i>\"Osmanlılarda 'kadı' sadece mahkemede oturmazdı; narh fiyatlarını belirler, çarşıyı denetler, vakıfları kontrol eder ve yetimlerin haklarını gözetirdi. Bu çok işlevli rol, kadıyı taşra yönetiminin hem yargıcı hem de belediye başkanı konumuna getirmişti.\"</i><br><br><b>Kadılık kurumunun Osmanlı yerel yönetimindeki yeri nedir?</b>",
        secenekler: [
            "A) Sadece dini nikah kıymak.",
            "B) Adalet, belediye hizmetleri ve toplumsal denetimi tek bir makamda birleştiren kilit rol.",
            "C) Sadece askeri vali yardımcılığı.",
            "D) Vergi toplama memurluğu.",
            "E) Medrese hocalığı ile sınırlı görev."
        ],
        cevap: "B) Adalet, belediye hizmetleri ve toplumsal denetimi tek bir makamda birleştiren kilit rol.",
        aciklama: "Kadı, merkezî otoritenin taşradaki 'vicdanı' ve 'denetçisi'dir; hukuki ve idari hayatın kesişim noktasındadır."
    },
    {
        soru: "<i>\"İstanbul'un fethinden sonra şehre yerleştirilen Museviler ve Ermeniler, imparatorluğun ticari ağlarını hem Avrupa hem de Doğu dünyası ile birleştiren birer köprü işlevi görmüşlerdir. Fatih'in bu 'ekonomik iskân' politikası, İstanbul'u küresel bir pazar haline getirmiştir.\"</i><br><br><b>Fatih'in bu politikasının İstanbul ekonomisine etkisi nedir?</b>",
        secenekler: [
            "A) Ticaretin sadece Müslümanların eline geçmesini sağlamak.",
            "B) Farklı cemaatlerin uzmanlıklarını kullanarak kenti uluslararası ticaretin merkezi yapmak.",
            "C) Şehri dış ticarete kapatmak.",
            "D) Gayrimüslimlerin mülk edinmesini yasaklamak.",
            "E) İpek Yolu'nu tamamen terk etmek."
        ],
        cevap: "B) Farklı cemaatlerin uzmanlıklarını kullanarak kenti uluslararası ticaretin merkezi yapmak.",
        aciklama: "Ticari yetenekleri olan grupların İstanbul'a çekilmesi, şehrin fetihten sonra hızla ekonomik bir refah ve canlılık kazanmasını sağlamıştır."
    },
    {
        soru: "<i>\"Osmanlı askeri gücünün 16. yüzyıldaki en özgün birimi olan 'yeniçeriler', Avrupa ordularının henüz tanışmadığı bir disiplin ve eğitim sistemine sahipti. Bekarlık zorunluluğu ve kışla yaşamı, onları sadece savaş odaklı profesyonel bir makine ordusuna dönüştürmüştü.\"</i><br><br><b>Yeniçeri ocağının klasik dönemdeki disiplininin kaynağı nedir?</b>",
        secenekler: [
            "A) Sadece gönüllülük esası.",
            "B) Kışla hayatı, bekarlık şartı ve sürekli profesyonel eğitim.",
            "C) Askerlerin istedikleri işi yapabilme özgürlüğü.",
            "D) Ordunun sadece savaş zamanı toplanması.",
            "E) Askerlerin sadece Balkan kökenli olması."
        ],
        cevap: "B) Kışla hayatı, bekarlık şartı ve sürekli profesyonel eğitim.",
        aciklama: "Yeniçerilerin kişisel hayatlarının ordu hizmetine tam kurban edilmesi, onları dönemin en disiplinli ve vurucu askeri gücü yapmıştır."
    },
    {
        soru: "<i>\"Osmanlı 'Adalet Dairesi' felsefesi: Hükümdar adaletle hükmederse reaya (halk) zenginleşir, halk zenginleşirse vergi artar, vergi artarsa ordu güçlenir, ordu güçlü olursa hükümdar emniyette olur. Bu döngü, devletin varlık sebebidir.\"</i><br><br><b>Bu metne göre 'adalet' kavramının devlet aygıtındaki asıl önemi nedir?</b>",
        secenekler: [
            "A) Sadece dini bir vecibe olması.",
            "B) Ekonomik ve askeri sistemin sağlıklı işlemesini sağlayan kurucu ve motor güç olması.",
            "C) Sadece mahkemelerdeki davaları bitirmesi.",
            "D) Padişahı halktan üstün kılması.",
            "E) Sadece askeri cezaları belirlemesi."
        ],
        cevap: "B) Ekonomik ve askeri sistemin sağlıklı işlemesini sağlayan kurucu ve motor güç olması.",
        aciklama: "Adalet, Osmanlı'da sadece ahlaki bir kavram değil, ekonomik verimliliği ve askeri gücü besleyen sistemik bir zorunluluktur."
    },
    {
        soru: "<i>\"Vakıf kütüphanelerinde el yazması eserlerin korunması için kullanılan 'mürekkep balığı' gibi teknik yöntemler, dönemin kimya ve sanat birikimini yansıtır. Her kitabın bir sanat eseri olarak ciltlenmesi ve korunması, bilgiye duyulan hürmetin fiziksel göstergesidir.\"</i><br><br><b>Kitap sanatlarının (hat, cilt, tezhip) gelişmesi neyi kanıtlar?</b>",
        secenekler: [
            "A) Matbaanın yokluğunun hiçbir sorun yaratmadığını.",
            "B) Bilginin içeriği kadar estetik sunumuna ve korunmasına da büyük bir medeni değer atfedildiğini.",
            "C) Kitapların sadece zenginler için olduğunu.",
            "D) Kağıt üretiminin yetersizliğini.",
            "E) Kitapların sadece dini amaçla kullanıldığını."
        ],
        cevap: "B) Bilginin içeriği kadar estetik sunumuna ve korunmasına da büyük bir medeni değer atfedildiğini.",
        aciklama: "Görsel ve teknik özen, yazılı kültüre ve ilme duyulan saygının Osmanlı sanatındaki en somut ifadesidir."
    },
    {
        soru: "<i>\"Osmanlı tıp tarihinde hastaların tedavi süreçleri 'mizaj' teorisine göre kişiselleştirilirdi. Hekim, hastanın sadece hastalığını değil; beslenme alışkanlığını, yaşadığı çevreyi ve psikolojik halini de reçetesine eklerdi. Bu, bütüncül bir tıp anlayışıdır.\"</i><br><br><b>Osmanlı tıp anlayışının 'bütüncül' (holistik) karakteri hangisidir?</b>",
        secenekler: [
            "A) Sadece tek bir ilaçla her hastalığı iyileştirmeye çalışmak.",
            "B) Hastayı fiziksel, ruhsal ve çevresel faktörlerle bir bütün olarak değerlendirmek.",
            "C) Modern tıbbı tamamen reddetmek.",
            "D) Sadece saray hekimlerinin başarılı olması.",
            "E) Tedaviyi sadece kış aylarında yapmak."
        ],
        cevap: "B) Hastayı fiziksel, ruhsal ve çevresel faktörlerle bir bütün olarak değerlendirmek.",
        aciklama: "İnsan sağlığını ruh ve beden dengesi olarak gören Osmanlı tıbbı, hastayı mekanik bir makine değil, yaşayan bir denge olarak görür."
    },
    {
        soru: "<i>\"17. yüzyılın başında Osmanlı devlet adamları, medreselerdeki eğitimin bozulmaya başladığını ve liyakatsiz atamaların ('beşik ulemalığı') arttığını rapor etmişlerdir. Bu eleştiriler, sistemin mükemmeliyetini değil, zamanla uğradığı aşınmayı ve reform ihtiyacını gösterir.\"</i><br><br><b>'Beşik ulemalığı' kavramı Osmanlı eğitimindeki hangi sorunu tanımlar?</b>",
        secenekler: [
            "A) Eğitimde bebek bakım derslerinin verilmesi.",
            "B) Alimlerin çocuklarının daha bebekken 'alim' sayılmasıyla liyakat sisteminin bozulması.",
            "C) Medreselerin sadece çocuklara hitap etmesi.",
            "D) Kitapların sadece el yazması olması kuralı.",
            "E) Eğitim süresinin çok kısa olması."
        ],
        cevap: "B) Alimlerin çocuklarının daha bebekken 'alim' sayılmasıyla liyakat sisteminin bozulması.",
        aciklama: "Babasının makamı sayesinde çocuklara unvan verilmesi, Osmanlı'nın en temel kurumu olan 'liyakat' (başarı/yetenek) sistemini çökerten bir yozlaşmadır."
    },
    {
        soru: "<i>\"Osmanlı askeri lojistiğinde 'yaya' ve 'müsellem' birliklerinin yol yapımında kullanılması, ordunun sadece silahlı güç değil; aynı zamanda bir 'mühendislik ve bayındırlık' birimi olduğunu da kanıtlamaktadır.\"</i><br><br><b>Yaya ve müsellemlerin lojistik rolleri neyi ifade eder?</b>",
        secenekler: [
            "A) Askerlerin savaştan kaçtığını.",
            "B) Ordunun fethi kolaylaştırmak için altyapı hizmetlerini de üstlenen organize bir yapı olduğunu.",
            "C) Osmanlı'nın sivil işçisinin hiç olmadığını.",
            "D) Yolların her zaman bozuk olduğunu.",
            "E) Savaşların sadece yollar üzerinde yapıldığını."
        ],
        cevap: "B) Ordunun fethi kolaylaştırmak için altyapı hizmetlerini de üstlenen organize bir yapı olduğunu.",
        aciklama: "Yol ve köprü gibi altyapı çalışmaları, ordunun hareket hızını artıran ve fethin kalıcılığını sağlayan teknik bir askeri gerekliliktir."
    },
    {
        soru: "<i>\"Osmanlı İmparatorluğu'nun cihan devleti olma süreci; kılıcın fethettiği, adaletin yönettiği ve ilmin kalıcı kıldığı bütünleşik bir medeniyet yürüyüşüdür. Bu üç kanattan biri eksik kalsaydı, 600 yıllık süreklilik mümkün olamazdı.\"</i><br><br><b>Metnin ana vurgusu aşağıdakilerden hangisidir?</b>",
        secenekler: [
            "A) Sadece askeri gücün devleti ayakta tuttuğu.",
            "B) İmparatorluğun başarısının askeri güç, adalet ve bilim arasındaki uyumlu iş birliğine dayandığı.",
            "C) Adaletin bilimden daha önemli olduğu.",
            "D) Osmanlı'nın sadece fetihlerle ilgilendiği.",
            "E) Bilimin sadece İstanbul'da kalması gerektiği."
        ],
        cevap: "B) İmparatorluğun başarısının askeri güç, adalet ve bilim arasındaki uyumlu iş birliğine dayandığı.",
        aciklama: "Gücün (ordu) meşruiyetle (adalet) ve kurumsal derinlikle (ilim) birleşmesi, Osmanlı'nın uzun ömürlü ve görkemli bir cihan devleti olmasını sağlamıştır."
    }
];
